import express from 'express';
import passport from 'passport';
import { AuthService } from '../services/auth.js';

const router = express.Router();

/**
 * POST /api/auth/google
 * Initiate Google OAuth2 authentication
 */
router.post('/google', async (req, res, next) => {
  try {
    // This would typically be handled by the frontend redirecting to Google
    // For now, we'll handle the callback directly
    res.json({
      success: true,
      message: 'Redirect to Google OAuth2',
      redirectUrl: `https://accounts.google.com/oauth/authorize?client_id=${process.env.GOOGLE_CLIENT_ID}&redirect_uri=${encodeURIComponent(process.env.GOOGLE_CALLBACK_URL!)}&response_type=code&scope=openid%20email%20profile`,
    });
  } catch (error) {
    console.error('Google OAuth2 initiation error:', error);
    res.status(500).json({
      success: false,
      error: {
        code: 'OAUTH_INITIATION_FAILED',
        message: 'Failed to initiate Google OAuth2',
      },
    });
  }
});

/**
 * GET /api/auth/google/callback
 * Handle Google OAuth2 callback
 */
router.get('/google/callback',
  passport.authenticate('google', { session: false }),
  async (req: any, res) => {
    try {
      if (!req.user) {
        return res.status(401).json({
          success: false,
          error: {
            code: 'AUTHENTICATION_FAILED',
            message: 'Google authentication failed',
          },
        });
      }

      // Generate JWT tokens
      const tokens = AuthService.generateTokens(req.user);

      // Set HTTP-only cookies for refresh token
      res.cookie('refreshToken', tokens.refreshToken, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'strict',
        maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
      });

      res.json({
        success: true,
        data: {
          user: {
            id: req.user.id,
            email: req.user.email,
            name: req.user.name,
            role: req.user.role,
            familyId: req.user.familyId,
          },
          tokens: {
            accessToken: tokens.accessToken,
            expiresIn: tokens.expiresIn,
          },
        },
      });
    } catch (error) {
      console.error('Google OAuth2 callback error:', error);
      res.status(500).json({
        success: false,
        error: {
          code: 'AUTHENTICATION_ERROR',
          message: 'Authentication process failed',
        },
      });
    }
  }
);

/**
 * POST /api/auth/refresh
 * Refresh access token using refresh token
 */
router.post('/refresh', async (req, res) => {
  try {
    const { refreshToken } = req.body;

    if (!refreshToken) {
      return res.status(400).json({
        success: false,
        error: {
          code: 'MISSING_REFRESH_TOKEN',
          message: 'Refresh token is required',
        },
      });
    }

    const tokens = await AuthService.refreshAccessToken(refreshToken);

    if (!tokens) {
      return res.status(401).json({
        success: false,
        error: {
          code: 'INVALID_REFRESH_TOKEN',
          message: 'Refresh token is invalid or expired',
        },
      });
    }

    // Update refresh token cookie
    res.cookie('refreshToken', tokens.refreshToken, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
    });

    res.json({
      success: true,
      data: {
        accessToken: tokens.accessToken,
        expiresIn: tokens.expiresIn,
      },
    });
  } catch (error) {
    console.error('Token refresh error:', error);
    res.status(500).json({
      success: false,
      error: {
        code: 'TOKEN_REFRESH_FAILED',
        message: 'Failed to refresh access token',
      },
    });
  }
});

/**
 * POST /api/auth/logout
 * Invalidate user session and tokens
 */
router.post('/logout', (req, res) => {
  try {
    // Clear refresh token cookie
    res.clearCookie('refreshToken');

    res.json({
      success: true,
      message: 'Successfully logged out',
    });
  } catch (error) {
    console.error('Logout error:', error);
    res.status(500).json({
      success: false,
      error: {
        code: 'LOGOUT_FAILED',
        message: 'Failed to logout',
      },
    });
  }
});

/**
 * GET /api/auth/profile
 * Get current user profile
 */
router.get('/profile', async (req, res) => {
  try {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];

    if (!token) {
      return res.status(401).json({
        success: false,
        error: {
          code: 'MISSING_TOKEN',
          message: 'Access token is required',
        },
      });
    }

    const user = await AuthService.getUserFromToken(token);

    if (!user) {
      return res.status(401).json({
        success: false,
        error: {
          code: 'INVALID_TOKEN',
          message: 'Invalid or expired access token',
        },
      });
    }

    res.json({
      success: true,
      data: {
        user: {
          id: user.id,
          email: user.email,
          name: user.name,
          role: user.role,
          familyId: user.familyId,
          createdAt: user.createdAt,
          updatedAt: user.updatedAt,
        },
        family: user.family ? {
          id: user.family.id,
          name: user.family.name,
        } : null,
      },
    });
  } catch (error) {
    console.error('Profile fetch error:', error);
    res.status(500).json({
      success: false,
      error: {
        code: 'PROFILE_FETCH_FAILED',
        message: 'Failed to fetch user profile',
      },
    });
  }
});

export default router;